using GmpCompanyCollector.App.Models;using GmpCompanyCollector.App.Utilities;using GmpCompanyCollector.App.Services;using ClosedXML.Excel;using Xunit;
namespace GmpCompanyCollector.Tests;
public class ApiUrlBuilderTests{[Fact]public void DecodingKeyIsEncoded(){var u=ApiUrlBuilder.Build("getDrugBsshListInq",new(){ServiceKey="a+b/="},1).ToString();Assert.Contains("a%2Bb%2F%3D",u);}[Fact]public void EncodingKeyIsNotDoubleEncoded(){var u=ApiUrlBuilder.Build("getDrugBsshListInq",new(){ServiceKey="a%2Bb%2F%3D",KeyMode=ServiceKeyMode.Encoding},1).ToString();Assert.Contains("a%2Bb%2F%3D",u);Assert.DoesNotContain("%252B",u);}[Fact]public void KoreanCompanyNameEncodedAndEmptyExcluded(){var u=ApiUrlBuilder.Build("getDrugBsshListInq",new(){ServiceKey="k",Entrps="하나제약",Induty=""},1).ToString();Assert.Contains("Entrps=",u);Assert.DoesNotContain("Induty=&",u);}[Fact]public void DateAndPermitIncluded(){var u=ApiUrlBuilder.Build("getDrugBsshItemInq",new(){ServiceKey="k",PrmisnNo="2389"},1).ToString();Assert.Contains("Prmisn_no=2389",u);}}
public class JsonParserTests{[Fact]public void ParsesResponseWrapperArray(){var r=ApiResponseParser.ParseCompanyList("""{"response":{"header":{"resultCode":"00"},"body":{"pageNo":1,"numOfRows":1,"totalCount":1,"items":{"item":[{"ENTRPS":"하나제약㈜","PRMISN_NO":"2389"}]}}}}""");Assert.Single(r.Body.Items);Assert.Equal("하나제약",r.Body.Items[0].NormalizedEntrps);}[Fact]public void ParsesTopLevelSingleObjectAndNull(){var r=ApiResponseParser.ParseCompanyList("""{"header":{},"body":{"items":{"item":{"ENTRPS":null,"PRMISN_DT":"19880509"}}}}""");Assert.Equal("",r.Body.Items[0].Entrps);Assert.Equal("1988-05-09",r.Body.Items[0].PrmisnDateDisplay);}[Fact]public void ParsesNoData(){var r=ApiResponseParser.ParseCompanyList("""{"response":{"header":{},"body":{"items":[]}}}""");Assert.Empty(r.Body.Items);}}
public class XmlParserTests{[Fact]public void ParsesCompanyXml(){var r=ApiResponseParser.ParseCompanyList("<response><header><resultCode>00</resultCode></header><body><totalCount>1</totalCount><items><item><ENTRPS>한빛</ENTRPS><ADRES>경기도 화성시 향남읍</ADRES></item></items></body></response>");Assert.Equal("경기도",r.Body.Items[0].Sido);}[Fact]public void ParsesFactoryXml(){var r=ApiResponseParser.ParseFactoryDetails("<response><header><resultCode>00</resultCode></header><body><items><item><FCTRY_ADDR1>서울특별시 강남구</FCTRY_ADDR1><FCTRY_ADDR2>테헤란로</FCTRY_ADDR2><TELNO>02-000</TELNO></item></items></body></response>");Assert.Equal("서울특별시 강남구 테헤란로",r.Body.Items[0].CombinedFactoryAddress);}[Fact]public void ParsesOpenApiError(){var r=ApiResponseParser.ParseCompanyList("<OpenAPI_ServiceResponse><cmmMsgHeader><errMsg>SERVICE ERROR</errMsg><returnAuthMsg>SERVICE_KEY_IS_NOT_REGISTERED_ERROR</returnAuthMsg><returnReasonCode>30</returnReasonCode></cmmMsgHeader></OpenAPI_ServiceResponse>");Assert.False(r.IsSuccess);Assert.Contains("등록되지",r.Header.ResultMsg);}[Fact]public void EmptyItems(){var r=ApiResponseParser.ParseCompanyList("<response><header/><body><items/></body></response>");Assert.Empty(r.Body.Items);}}
public class PaginationAndCleanTests{[Fact]public void CalculatesPages(){Assert.Equal(37,ApiUrlBuilder.CalculateTotalPages(3688,100));Assert.Equal(0,ApiUrlBuilder.CalculateTotalPages(0,100));}[Fact]public void CleanersWork(){Assert.Equal("하나제약",CompanyNameNormalizer.Normalize("하나제약㈜"));Assert.Equal(("1988-05-09",true),DateParser.Parse("19880509"));Assert.False(DateParser.Parse("19881340").Valid);Assert.Equal("경기도",AddressParser.Parse("경기도 화성시 향남읍").Sido);Assert.Equal("A B",AddressParser.Combine("A","B"));}[Fact]public void DuplicateMarking(){var c=new List<CompanyListItem>{new(){PrmisnNo="1",Induty="A",Entrps="B",Adres="C"},new(){PrmisnNo="1",Induty="A",Entrps="B",Adres="C"}};new StatisticsService().MarkDuplicates(c,new List<FactoryDetailItem>());Assert.True(c[0].IsDuplicate);}}
public class ExportTests{[Fact]public void ExcelSheetsAndTextValues(){var f=Path.GetTempFileName()+".xlsx";new ExcelExportService().Export(f,new[]{new CompanyListItem{Entrps="한글",PrmisnNo="0123"}},new[]{new FactoryDetailItem{Entrps="한글",Telno="010"}});using var wb=new XLWorkbook(f);Assert.NotNull(wb.Worksheet("업체목록"));Assert.NotNull(wb.Worksheet("제조소상세"));Assert.Contains("0123",wb.Worksheet("업체목록").Cell(2,8).GetString());Assert.Contains("010",wb.Worksheet("제조소상세").Cell(2,11).GetString());}}
